// Inflación acumulada desde cada mes hasta May-2026 (para "Var. Real")
const MONTHS = Object.keys(MACRO).sort();
const inflAcum = (() => {
  const r = {};
  MONTHS.forEach((ym, i) => {
    let f = 1;
    for (let j = i + 1; j < MONTHS.length; j++) f *= (1 + MACRO[MONTHS[j]].ipc / 100);
    r[ym] = f; // factor para llevar ese mes a May-2026
  });
  return r;
})();

// Inflación acumulada total Ene-25 → May-26
const INF_TOTAL_PCT = ((inflAcum["2025-01"] - 1) * 100).toFixed(1);

