// ═══════════════════════════════════════════════════════════════════
// CONVERSIÓN
// modo: "ars" = nominales | "usd" = blue de cada mes
// Para "Variación Real" no es un modo de display sino un indicador
// ═══════════════════════════════════════════════════════════════════
function convertRow(row, modo) {
  if (modo === "usd") {
    const tc = MACRO[row.ym]?.blue || 1;
    return { ...row, ventas: row.ventas / tc, tarifa: (row.tarifa||0) / tc };
  }
  return { ...row };
}
function convertDs(data, modo) { return data.map(r => convertRow(r, modo)); }

// Crecimiento real = crecimiento nominal - inflación del período
// Si a.ym → b.ym: inflación acumulada entre ambos meses
function inflEntreMeses(ymA, ymB) {
  const iA = MONTHS.indexOf(ymA), iB = MONTHS.indexOf(ymB);
  if (iA < 0 || iB < 0 || iB <= iA) return null;
  let f = 1;
  for (let i = iA + 1; i <= iB; i++) f *= (1 + MACRO[MONTHS[i]].ipc / 100);
  return (f - 1) * 100;
}
function varReal(nominal_pct, inflacion_pct) {
  if (nominal_pct == null || inflacion_pct == null) return null;
  return ((1 + nominal_pct/100) / (1 + inflacion_pct/100) - 1) * 100;
}

// ═══════════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════════
const ML = {"01":"Ene","02":"Feb","03":"Mar","04":"Abr","05":"May","06":"Jun",
            "07":"Jul","08":"Ago","09":"Sep","10":"Oct","11":"Nov","12":"Dic"};
const shortLbl = ym => { const [y,m]=ym.split("-"); return `${ML[m]} ${y.slice(2)}`; };
const getRow   = (data,ym) => data.find(d=>d.ym===ym) || null;
const prevM    = ym => { const[y,m]=ym.split("-").map(Number); return m===1?`${y-1}-12`:`${y}-${String(m-1).padStart(2,"0")}`; };
const prevY    = ym => { const[y,m]=ym.split("-"); return `${Number(y)-1}-${m}`; };
const pct      = (a,b) => b ? ((a-b)/b)*100 : null;
const diffCol  = n => n==null||!isFinite(n)?"#94A3B8":n>=0?"#059669":"#DC2626";
const diffBg   = n => n==null||!isFinite(n)?"#F1F5F9":n>=0?"#ECFDF5":"#FEF2F2";
const arw      = n => n==null||!isFinite(n)?"":n>=0?"▲":"▼";

function fmtV(n, modo) {
  if (n==null) return "—";
  if (modo==="usd") {
    if (Math.abs(n)>=1e6) return `U$S ${(n/1e6).toFixed(2)}M`;
    if (Math.abs(n)>=1e3) return `U$S ${(n/1e3).toFixed(1)}k`;
    return `U$S ${Math.round(n).toLocaleString("es-AR")}`;
  }
  if (Math.abs(n)>=1e9) return `$${(n/1e9).toFixed(2)}B`;
  if (Math.abs(n)>=1e6) return `$${(n/1e6).toFixed(1)}M`;
  if (Math.abs(n)>=1e3) return `$${(n/1e3).toFixed(1)}k`;
  return `$${Math.round(n).toLocaleString("es-AR")}`;
}
function fmtFull(n, modo) {
  if (n==null) return "—";
  if (modo==="usd") return `U$S ${Math.round(n).toLocaleString("es-AR")}`;
  return `$${Math.round(n).toLocaleString("es-AR")}`;
}
function fmtDiff(n, modo) {
  if (n==null) return "—";
  const s = n>=0?"+":"";
  if (modo==="usd") {
    if (Math.abs(n)>=1e3) return `${s}U$S ${Math.round(n/1e3).toLocaleString("es-AR")}k`;
    return `${s}U$S ${Math.round(n).toLocaleString("es-AR")}`;
  }
  if (Math.abs(n)>=1e6) return `${s}$${(n/1e6).toFixed(1)}M`;
  if (Math.abs(n)>=1e3) return `${s}$${Math.round(n/1e3).toLocaleString("es-AR")}k`;
  return `${s}$${Math.round(n).toLocaleString("es-AR")}`;
}
const fmtPct = n => n==null||!isFinite(n)?"":` (${n>=0?"+":""}${n.toFixed(1)}%)`;
const fmtPctBadge = n => n==null||!isFinite(n)?"—":`${n>=0?"+":""}${n.toFixed(1)}%`;
function fmtYAxis(v, modo) {
  if (modo==="usd") return `U$S ${(v/1e3).toFixed(0)}k`;
  return `$${(v/1e6).toFixed(0)}M`;
}

