function ModoSelector({ modo, onChange }) {
  const opts = [
    { v:"ars", label:"$ ARS",     title:"Pesos nominales" },
    { v:"usd", label:"U$S Blue",  title:"Dólar blue de cada mes (Ámbito)" },
  ];
  return (
    <div style={{ display:"flex", alignItems:"center", gap:6 }}>
      <span style={{ fontSize:10, fontWeight:700, color:C.muted, textTransform:"uppercase", letterSpacing:"0.07em" }}>Vista</span>
      {opts.map(({v,label,title}) => {
        const sel = modo===v;
        return (
          <button key={v} title={title} onClick={()=>onChange(v)} style={{
            background: sel ? (v==="usd"?"#92400E":C.accent) : "#fff",
            border: `1px solid ${sel?(v==="usd"?"#92400E":C.accent):C.border}`,
            color: sel?"#fff":C.sub,
            borderRadius:7, padding:"5px 12px", fontSize:11, fontWeight:700, cursor:"pointer",
          }}>{label}</button>
        );
      })}
    </div>
  );
}

// Badge con el modo activo + nota de Var. Real
function ModoBanner({ modo, currentYm }) {
  const ipcNote = modo==="usd"
    ? `TC: $${MACRO[currentYm]?.blue?.toLocaleString("es-AR")} / USD (promedio ${shortLbl(currentYm)})`
    : "Ventas netas sin IVA · Con factura: neto ÷ 1.21 · Sin comprobante: al 100%";
  const bgColor = modo==="usd" ? "#FFFBEB" : "#EFF6FF";
  const bdColor = modo==="usd" ? "#FCD34D" : "#BFDBFE";
  const txColor = modo==="usd" ? "#92400E" : "#1D4ED8";
  const icon    = modo==="usd" ? "💵" : "💰";
  const label   = modo==="usd" ? "U$S BLUE · CADA MES" : "ARS NOMINALES";
  return (
    <div style={{ display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
      <span style={{ display:"inline-flex", alignItems:"center", gap:5,
        background:bgColor, border:`1px solid ${bdColor}`,
        borderRadius:20, padding:"4px 12px",
        fontSize:10, fontWeight:800, color:txColor, letterSpacing:"0.06em" }}>
        {icon} {label}
      </span>
      <span style={{ fontSize:11, color:C.muted }}>{ipcNote}</span>
    </div>
  );
}

// Pill de Variación Real
function VarRealPill({ nominalPct, ymBase, ymTarget }) {
  const inf = inflEntreMeses(ymBase, ymTarget);
  const real = varReal(nominalPct, inf);
  if (real==null || inf==null) return null;
  const col = real>=0 ? C.green : C.red;
  const bg  = real>=0 ? "#ECFDF5" : "#FEF2F2";
  return (
    <div style={{ display:"flex", alignItems:"center", gap:6, flexWrap:"wrap" }}>
      <span style={{ background:bg, color:col, borderRadius:6,
        padding:"3px 10px", fontSize:12, fontWeight:800 }}>
        {real>=0?"▲":"▼"} {fmtPctBadge(real)} real
      </span>
      <span style={{ fontSize:10, color:C.muted }}>
        Inflación período: {fmtPctBadge(inf)} · Nominal: {fmtPctBadge(nominalPct)}
      </span>
    </div>
  );
}

function CompRow({ label, diff, nomPct, ymBase, ymTarget, modo, showReal, isMoney=true }) {
  const col=diffCol(nomPct), bg=diffBg(nomPct), ar=arw(nomPct);
  const inf = showReal && ymBase && ymTarget ? inflEntreMeses(ymBase, ymTarget) : null;
  const real = inf!=null ? varReal(nomPct, inf) : null;
  const diffStr = typeof diff === "number"
    ? isMoney
      ? fmtDiff(diff, modo)
      : (diff>=0?"+":"")+Math.round(diff).toLocaleString("es-AR")
    : diff;
  return (
    <div style={{ background:bg, borderRadius:6, padding:"5px 8px", marginBottom:2 }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <span style={{ fontSize:9, color:C.muted, fontWeight:600, textTransform:"uppercase", letterSpacing:"0.05em" }}>{label}</span>
        <span style={{ fontSize:11, fontWeight:700, color:col }}>
          {ar} {diffStr}{fmtPct(nomPct)}
        </span>
      </div>
      {real!=null && (
        <div style={{ display:"flex", justifyContent:"flex-end", marginTop:2 }}>
          <span style={{ fontSize:9, fontWeight:700,
            color:real>=0?C.realGreen:C.red,
            background:real>=0?"#D1FAE5":"#FEE2E2",
            borderRadius:4, padding:"1px 6px" }}>
            Var. real: {fmtPctBadge(real)}
          </span>
        </div>
      )}
    </div>
  );
}

function KpiCard({ label, icon, value, diffMes, pctMes, diffAnio, pctAnio, accent, modo, currentYm }) {
  const pYm  = prevM(currentYm);
  const pYYm = prevY(currentYm);
  const isMoney = label !== "Socios Activos";
  return (
    <div style={{ background:C.card, border:`1px solid ${C.border}`, borderRadius:12,
      padding:"18px 20px", flex:1, minWidth:0, boxShadow:"0 1px 3px rgba(0,0,0,0.06)" }}>
      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
        <div style={{ width:30,height:30,borderRadius:8, background:`${accent||C.accent}18`,
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:14 }}>{icon}</div>
        <span style={{ fontSize:10,fontWeight:700,letterSpacing:"0.07em",color:C.sub,textTransform:"uppercase" }}>{label}</span>
      </div>
      <div style={{ fontSize:26,fontWeight:800,color:C.text,letterSpacing:"-0.03em",marginBottom:10 }}>{value}</div>
      <CompRow label="vs mes anterior" diff={diffMes}  nomPct={pctMes}  ymBase={pYm}  ymTarget={currentYm} modo={modo} showReal={modo==="ars"&&isMoney} isMoney={isMoney} />
      <CompRow label="vs año anterior" diff={diffAnio} nomPct={pctAnio} ymBase={pYYm} ymTarget={currentYm} modo={modo} showReal={modo==="ars"&&isMoney} isMoney={isMoney} />
    </div>
  );
}

// Tooltip del gráfico
const ChartTip = ({ active, payload, label, barColor, modo }) => {
  if (!active||!payload?.length) return null;
  const ym = payload[0]?.payload?.ym;
  return (
    <div style={{ background:"#fff",border:`1px solid ${C.border}`,borderRadius:8,
      padding:"10px 14px",boxShadow:"0 4px 12px rgba(0,0,0,0.1)" }}>
      <div style={{ fontSize:11,color:C.muted,marginBottom:3 }}>{label}</div>
      <div style={{ fontSize:14,fontWeight:700,color:barColor||C.accent }}>{fmtFull(payload[0].value,modo)}</div>
      {modo==="usd"&&ym&&<div style={{ fontSize:10,color:C.muted,marginTop:2 }}>TC: ${MACRO[ym]?.blue?.toLocaleString("es-AR")}/USD</div>}
    </div>
  );
};

function VentasChart({ data, barColor, currentYm, modo }) {
  const cd = data.map(d=>({ name:shortLbl(d.ym), ym:d.ym, ventas:Math.round(d.ventas) }));
  return (
    <ResponsiveContainer width="100%" height={200}>
      <BarChart data={cd} barSize={cd.length<=12?28:18} margin={{ top:4,right:4,bottom:0,left:0 }}>
        <CartesianGrid vertical={false} stroke={C.divider} />
        <XAxis dataKey="name" tick={{ fill:C.muted,fontSize:cd.length<=12?10:9 }} axisLine={false} tickLine={false} interval={0} />
        <YAxis tick={{ fill:C.muted,fontSize:10 }} axisLine={false} tickLine={false}
          tickFormatter={v=>fmtYAxis(v,modo)} width={60} />
        <Tooltip content={<ChartTip barColor={barColor} modo={modo} />} cursor={{ fill:"rgba(0,0,0,0.04)" }} />
        <Bar dataKey="ventas" radius={[4,4,0,0]}>
          {cd.map(d=><Cell key={d.ym} fill={d.ym===currentYm?(barColor||C.accent):`${barColor||C.accent}55`} />)}
        </Bar>
      </BarChart>
    </ResponsiveContainer>
  );
}

function TarifaChart({ con, sin, modo }) {
  const merged = con.map(r => {
    const s = sin.find(x=>x.ym===r.ym);
    return { name:shortLbl(r.ym), ym:r.ym, con:Math.round(r.tarifa||0), sin:s?Math.round(s.tarifa||0):null };
  });
  return (
    <ResponsiveContainer width="100%" height={190}>
      <LineChart data={merged} margin={{ top:4,right:16,bottom:0,left:0 }}>
        <CartesianGrid vertical={false} stroke={C.divider} />
        <XAxis dataKey="name" tick={{ fill:C.muted,fontSize:9 }} axisLine={false} tickLine={false} interval={0} />
        <YAxis tick={{ fill:C.muted,fontSize:10 }} axisLine={false} tickLine={false}
          tickFormatter={v=>modo==="usd"?`U$S ${Math.round(v/1e3)}k`:`$${Math.round(v/1e3)}k`} width={60} />
        <Tooltip formatter={(v,n)=>[fmtFull(v,modo),n==="con"?"Con alquileres/prod.":"Sin alquileres/prod."]}
          contentStyle={{ border:`1px solid ${C.border}`,borderRadius:8,fontSize:12 }} />
        <Legend formatter={n=>n==="con"?"Con alquileres":"Sin alq. + prod."} wrapperStyle={{ fontSize:11 }} />
        <Line type="monotone" dataKey="con" stroke={C.accent} strokeWidth={2.5} dot={false} />
        <Line type="monotone" dataKey="sin" stroke={C.amber} strokeWidth={2.5} dot={false} strokeDasharray="5 3" />
      </LineChart>
    </ResponsiveContainer>
  );
}

function ComposicionChart({ modo }) {
  const data = RAW.con_alq.map(d => {
    const c = r => convertRow(r||{ventas:0,ym:d.ym,tarifa:0}, modo);
    return {
      name:shortLbl(d.ym), ym:d.ym,
      pileta:   Math.round(c(getRow(RAW.pileta,      d.ym)).ventas),
      gym:      Math.round(c(getRow(RAW.gym_fitness, d.ym)).ventas),
      colonia:  Math.round(c(getRow(RAW.colonia,     d.ym)).ventas),
      escuelas: Math.round(c(getRow(RAW.escuelas,    d.ym)).ventas),
    };
  });
  return (
    <ResponsiveContainer width="100%" height={200}>
      <BarChart data={data} barSize={18} margin={{ top:4,right:4,bottom:0,left:0 }}>
        <CartesianGrid vertical={false} stroke={C.divider} />
        <XAxis dataKey="name" tick={{ fill:C.muted,fontSize:9 }} axisLine={false} tickLine={false} interval={0} />
        <YAxis tick={{ fill:C.muted,fontSize:10 }} axisLine={false} tickLine={false}
          tickFormatter={v=>fmtYAxis(v,modo)} width={60} />
        <Tooltip formatter={(v,n)=>[fmtFull(v,modo),RUBROS[n]?.label||n]}
          contentStyle={{ border:`1px solid ${C.border}`,borderRadius:8,fontSize:11 }} />
        <Legend formatter={n=>RUBROS[n]?.label||n} wrapperStyle={{ fontSize:11 }} />
        <Bar dataKey="pileta"   stackId="a" fill={RUBROS.pileta.color} />
        <Bar dataKey="gym"      stackId="a" fill={RUBROS.gym_fitness.color} />
        <Bar dataKey="colonia"  stackId="a" fill={RUBROS.colonia.color} />
        <Bar dataKey="escuelas" stackId="a" fill={RUBROS.escuelas.color} radius={[4,4,0,0]} />
      </BarChart>
    </ResponsiveContainer>
  );
}

function AnalysisPanel({ rawData, currentYm, barColor, chartRange, onChartRangeChange, modo, alqFilter }) {
  const data = useMemo(()=>convertDs(rawData,modo),[rawData,modo]);
  const cur   = getRow(data, currentYm);
  const prev  = getRow(data, prevM(currentYm));
  const prevYr = getRow(data, prevY(currentYm));
  const col   = barColor||C.accent;
  const chartData = useMemo(()=>{
    const s=[...data].sort((a,b)=>a.ym.localeCompare(b.ym));
    return chartRange==="12"?s.slice(-12):s;
  },[data,chartRange]);

  if (!cur) return <div style={{ textAlign:"center",padding:40,color:C.muted,fontSize:13 }}>Sin datos para el período</div>;

  const kpis = [
    { label:"Ventas Netas", icon:"💰",
      value:fmtV(cur.ventas,modo),
      diffMes:prev?cur.ventas-prev.ventas:null, pctMes:prev?pct(cur.ventas,prev.ventas):null,
      diffAnio:prevYr?cur.ventas-prevYr.ventas:null, pctAnio:prevYr?pct(cur.ventas,prevYr.ventas):null },
    { label:"Socios Activos", icon:"👥",
      value:cur.socios.toLocaleString("es-AR"),
      diffMes:prev?cur.socios-prev.socios:null, pctMes:prev?pct(cur.socios,prev.socios):null,
      diffAnio:prevYr?cur.socios-prevYr.socios:null, pctAnio:prevYr?pct(cur.socios,prevYr.socios):null },
    { label:"Tarifa Promedio", icon:"📊",
      value:fmtV(cur.tarifa,modo),
      diffMes:prev?cur.tarifa-prev.tarifa:null, pctMes:prev?pct(cur.tarifa,prev.tarifa):null,
      diffAnio:prevYr?cur.tarifa-prevYr.tarifa:null, pctAnio:prevYr?pct(cur.tarifa,prevYr.tarifa):null },
  ];

  return (
    <div style={{ display:"flex",flexDirection:"column",gap:14 }}>
      <ModoBanner modo={modo} currentYm={currentYm} />
      {modo==="ars" && (
        <div style={{ background:"#F0FDF4",border:"1px solid #BBF7D0",borderRadius:8,
          padding:"7px 13px",fontSize:11,color:C.realGreen }}>
          💡 <strong>Var. Real</strong> — cada KPI muestra debajo la variación descontando la inflación INDEC del período
        </div>
      )}
      <div style={{ display:"flex",gap:12,flexWrap:"wrap" }}>
        {kpis.map(k=><KpiCard key={k.label} {...k} accent={col} modo={modo} currentYm={currentYm} />)}
      </div>
      <div style={{ background:C.card,border:`1px solid ${C.border}`,borderRadius:12,
        padding:"18px 20px",boxShadow:"0 1px 3px rgba(0,0,0,0.06)" }}>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14 }}>
          <span style={{ fontSize:10,fontWeight:700,letterSpacing:"0.07em",color:C.sub,textTransform:"uppercase" }}>
            Ventas Netas Mensuales
          </span>
          <div style={{ display:"flex",gap:6 }}>
            {[["12","Últ. 12 meses"],["all","Desde Ene 2025"]].map(([v,lbl])=>(
              <button key={v} onClick={()=>onChartRangeChange(v)} style={{
                background:chartRange===v?col:"transparent",
                border:`1px solid ${chartRange===v?col:C.border}`,
                color:chartRange===v?"#fff":C.sub,
                borderRadius:6,padding:"4px 11px",fontSize:11,fontWeight:600,cursor:"pointer"
              }}>{lbl}</button>
            ))}
          </div>
        </div>
        <VentasChart data={chartData} barColor={col} currentYm={currentYm} modo={modo} />
      </div>
    </div>
  );
}

